With PYTHON and WEBSERVICE options unchecked, emulators/virtualbox-ose fails to stage with error:

install -l rs /usr/ports/emulators/virtualbox-ose/work/stage/usr/local/share/virtualbox-ose/sdk /usr/ports/emulators/virtualbox-ose/work/stage/usr/local/lib/virtualbox
install: /usr/ports/emulators/virtualbox-ose/work/stage/usr/local/share/virtualbox-ose/sdk: realpath: No such file or directory
*** Error code 71

${MKDIR} in line 319 has a condition, ${RLN} seems to need one too:

@@ -328,7 +328,9 @@
        ${MKDIR} ${STAGEDIR}${VBOX_DIR}
        cd ${KMK_BUILDDIR}/bin && ${COPYTREE_SHARE} \
            "*.fd *.r0 *.rc *.so components" ${STAGEDIR}${VBOX_DIR}
+.if ${PORT_OPTIONS:MPYTHON} || ${PORT_OPTIONS:MWEBSERVICE}
        ${RLN} ${STAGEDIR}${DATADIR}/sdk ${STAGEDIR}${VBOX_DIR}
+.endif

        ${INSTALL_SCRIPT} ${WRKSRC}/src/VBox/Installer/freebsd/VBox.sh \
            ${STAGEDIR}${VBOX_DIR}
